import{_ as e,a as d,b as a}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as r,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Додавання каналу Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/cloudflare-r2.md","filePath":"uk-UA/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),c={name:"uk-UA/upload/cloudflare-r2.md"};function n(u,t,b,h,s,g){return r(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="додавання-каналу-cloudflare-r2" tabindex="-1">Додавання каналу Cloudflare R2 <a class="header-anchor" href="#додавання-каналу-cloudflare-r2" aria-label="Permalink to &quot;Додавання каналу Cloudflare R2&quot;">​</a></h1><h2 id="коли-це-наикращии-варіант" tabindex="-1">Коли це найкращий варіант <a class="header-anchor" href="#коли-це-наикращии-варіант" aria-label="Permalink to &quot;Коли це найкращий варіант&quot;">​</a></h2><p>Використовуйте Cloudflare R2, якщо:</p><ul><li>ваш сайт ImgBed уже розгорнутий у Cloudflare, і ви хочете зберігати файли в R2 bucket у тому самому обліковому записі;</li><li>не хочете окремо налаштовувати S3 endpoint, access key і secret key;</li><li>хочете, щоб читання й запис ішли через R2 binding у Worker або Pages з мінімальним налаштуванням.</li></ul><p>Коротко:</p><p>R2-канал не створюється вручну в адмін-панелі ImgBed. Спочатку потрібно прив&#39;язати R2 bucket до проєкту Cloudflare, а назва змінної прив&#39;язки має бути саме <code>img_r2</code>.</p><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><ul><li>Обліковий запис Cloudflare.</li><li>Уже створений R2 bucket.</li><li>Права на керування Cloudflare-проєктом, де розгорнуто ImgBed.</li></ul><h2 id="налаштування-в-cloudflare" tabindex="-1">Налаштування в Cloudflare <a class="header-anchor" href="#налаштування-в-cloudflare" aria-label="Permalink to &quot;Налаштування в Cloudflare&quot;">​</a></h2><h3 id="_1-створіть-r2-bucket" tabindex="-1">1. Створіть R2 bucket <a class="header-anchor" href="#_1-створіть-r2-bucket" aria-label="Permalink to &quot;1. Створіть R2 bucket&quot;">​</a></h3><ol><li>Увійдіть у Cloudflare Dashboard.</li><li>Відкрийте <code>R2 Object Storage</code>.</li><li>Натисніть Create bucket.</li><li>Виберіть назву bucket, наприклад <code>imgbed</code>.</li></ol><p>У цьому bucket зберігатимуться завантажені файли.</p><p><img src="'+e+'" alt="Створення R2 bucket" loading="lazy"></p><h3 id="_2-прив-яжіть-bucket-до-проєкту-imgbed" tabindex="-1">2. Прив&#39;яжіть bucket до проєкту ImgBed <a class="header-anchor" href="#_2-прив-яжіть-bucket-до-проєкту-imgbed" aria-label="Permalink to &quot;2. Прив&#39;яжіть bucket до проєкту ImgBed&quot;">​</a></h3><p>Місце прив&#39;язки залежить від типу розгортання:</p><table tabindex="0"><thead><tr><th>Тип розгортання</th><th>Де налаштовується binding</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Під час додавання binding важливі такі поля:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Значення</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Виберіть створений bucket.</td></tr></tbody></table><p>Назва змінної має бути точно <code>img_r2</code>. Завантаження, читання й видалення файлів R2 залежать саме від цієї назви binding.</p><h3 id="_3-розгорніть-проєкт-повторно" tabindex="-1">3. Розгорніть проєкт повторно <a class="header-anchor" href="#_3-розгорніть-проєкт-повторно" aria-label="Permalink to &quot;3. Розгорніть проєкт повторно&quot;">​</a></h3><p>Після збереження binding повторно розгорніть ImgBed, щоб runtime Worker або Pages отримав доступ до <code>img_r2</code>.</p><h2 id="що-ви-побачите-в-imgbed" tabindex="-1">Що ви побачите в ImgBed <a class="header-anchor" href="#що-ви-побачите-в-imgbed" aria-label="Permalink to &quot;Що ви побачите в ImgBed&quot;">​</a></h2><p>Коли binding R2 стане доступним, відкрийте:</p><ol><li>Системні налаштування.</li><li>Налаштування завантаження.</li><li>Канал <code>Cloudflare R2</code>.</li></ol><p>Система автоматично створює один фіксований канал:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Фіксоване значення</th></tr></thead><tbody><tr><td>Назва каналу</td><td><code>Cloudflare R2</code></td></tr><tr><td>Тип каналу</td><td><code>cfr2</code></td></tr><tr><td>Режим зберігання</td><td><code>binding</code></td></tr><tr><td>Джерело конфігурації</td><td>Environment binding</td></tr></tbody></table><p>Це фіксований канал через binding. Його не потрібно створювати кнопкою Add Channel, і його не можна видалити як звичайний канал.</p><h2 id="поля-які-можна-змінити-в-адмін-панелі" tabindex="-1">Поля, які можна змінити в адмін-панелі <a class="header-anchor" href="#поля-які-можна-змінити-в-адмін-панелі" aria-label="Permalink to &quot;Поля, які можна змінити в адмін-панелі&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Що робить</th><th>Обов&#39;язково</th></tr></thead><tbody><tr><td>Enable channel</td><td>Визначає, чи бере R2 участь у виборі каналу для завантаження.</td><td>Так</td></tr><tr><td>Account ID</td><td>Потрібен лише тоді, коли ввімкнені ліміти квоти й треба запитувати офіційне використання R2.</td><td>Рекомендовано, якщо ввімкнено квоти</td></tr><tr><td>Bucket name</td><td>Потрібен лише тоді, коли ввімкнені ліміти квоти й треба запитувати офіційне використання R2.</td><td>Рекомендовано, якщо ввімкнено квоти</td></tr><tr><td>Quota limit</td><td>Визначає, чи враховується місткість каналу під час вибору сховища.</td><td>Ні</td></tr><tr><td>Threshold</td><td>Зупиняє запис у цей канал після досягнення вказаного відсотка використання.</td><td>Так, якщо ввімкнено квоти</td></tr></tbody></table><p>Account ID можна скопіювати з інформаційної панелі облікового запису в Cloudflare dashboard. Заповнюйте його тільки тоді, коли хочете, щоб ImgBed запитував і контролював використання квоти R2.</p><p><img src="'+d+'" alt="Отримання Account ID" loading="lazy"></p><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><ol><li>Створіть R2 bucket у Cloudflare.</li><li>Відкрийте налаштування Cloudflare для проєкту ImgBed.</li><li>Додайте R2 bucket binding.</li><li>У полі <code>Variable name</code> вкажіть <code>img_r2</code>.</li><li>Виберіть створений R2 bucket.</li><li>Збережіть binding і повторно розгорніть ImgBed.</li><li>Поверніться до ImgBed -&gt; System Settings -&gt; Upload Settings.</li><li>Переконайтеся, що канал <code>Cloudflare R2</code> з&#39;явився та ввімкнений.</li></ol><p>Якщо хочете, щоб R2 враховувався під час вибору каналу за доступною місткістю, увімкніть quota limit, потім введіть Account ID, назву bucket, ліміт квоти й threshold перед збереженням.</p><p><img src="'+a+'" alt="Налаштування лімітів квоти" loading="lazy"></p><h2 id="як-перевірити" tabindex="-1">Як перевірити <a class="header-anchor" href="#як-перевірити" aria-label="Permalink to &quot;Як перевірити&quot;">​</a></h2><ul><li>Фіксований канал <code>Cloudflare R2</code> з&#39;являється в налаштуваннях завантаження.</li><li>На картці каналу видно, що він увімкнений.</li><li>Невеликий тестовий файл успішно завантажується, а повернене посилання відкривається нормально.</li><li>Якщо під час відкриття файлу з&#39;являється <code>R2 database binding is not configured</code>, runtime не отримав binding <code>img_r2</code>. Перевірте назву binding у Cloudflare й розгорніть проєкт повторно.</li></ul>',37)])])}const k=l(c,[["render",n]]);export{f as __pageData,k as default};
